using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummarizationService
{
    string Summarize(string documentText, int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization service that selects the most relevant sentences
/// from a document based on word frequency scoring.
/// </summary>
public partial class ExtractiveSummarizationService : IDocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "in", "on", "at", "to", "for",
        "of", "with", "by", "from", "is", "are", "was", "were", "be", "been",
        "being", "have", "has", "had", "do", "does", "did", "will", "would",
        "could", "should", "may", "might", "shall", "can", "need", "dare",
        "it", "its", "this", "that", "these", "those", "i", "you", "he", "she",
        "we", "they", "me", "him", "her", "us", "them", "my", "your", "his",
        "our", "their", "what", "which", "who", "whom", "where", "when", "how",
        "not", "no", "nor", "as", "if", "then", "else", "so", "than", "too",
        "very", "just", "about", "above", "after", "again", "all", "also", "am"
    };

    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scoredSentences = ScoreSentences(sentences, wordFrequencies);

        // Select top-scoring sentences, preserving original order
        var topIndices = scoredSentences
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .OrderBy(i => i)
            .ToList();

        var summarySentences = topIndices.Select(i => sentences[i]);
        return string.Join(" ", summarySentences);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        var matches = SentenceRegex().Matches(text);
        return matches
            .Select(m => m.Value.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            var words = WordRegex().Matches(sentence);
            foreach (Match word in words)
            {
                var w = word.Value.ToLowerInvariant();
                if (!StopWords.Contains(w) && w.Length > 1)
                {
                    frequencies[w] = frequencies.GetValueOrDefault(w, 0) + 1;
                }
            }
        }

        return frequencies;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences, Dictionary<string, int> wordFrequencies)
    {
        var maxFreq = wordFrequencies.Values.DefaultIfEmpty(1).Max();
        var scored = new List<(int Index, double Score)>();

        for (int i = 0; i < sentences.Count; i++)
        {
            var words = WordRegex().Matches(sentences[i]);
            double score = 0;

            foreach (Match word in words)
            {
                var w = word.Value.ToLowerInvariant();
                if (wordFrequencies.TryGetValue(w, out int freq))
                {
                    score += (double)freq / maxFreq;
                }
            }

            // Normalize by sentence length to avoid bias toward longer sentences
            if (words.Count > 0)
                score /= words.Count;

            scored.Add((i, score));
        }

        return scored;
    }

    [GeneratedRegex(@"[^.!?]*[.!?]+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b\w+\b", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizationService _summarizationService;

    public SummarizeController(IDocumentSummarizationService summarizationService)
    {
        _summarizationService = summarizationService;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizationService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

